/* Test for non-alarm signal accumulation issue */
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pthread.h>
#include <string.h>
#include <errno.h>

#define NUM_SIGNALS 20

volatile int signal_count = 0;
volatile int done = 0;
pthread_t sleep_thread;

void sigusr1_handler(int sig) {
    signal_count++;
}

void* sleep_thread_func(void* arg) {
    printf("Sleep thread started (tid=%ld)\n", (long)pthread_self());
    while (!done) {
        sleep(1);
    }
    printf("Sleep thread exiting, received %d signals\n", signal_count);
    return NULL;
}

void* sender_thread_func(void* arg) {
    printf("Sender thread started (tid=%ld)\n", (long)pthread_self());

    /* Wait a bit for sleep thread to start */
    usleep(100000);

    /* Send many SIGUSR1 signals rapidly to the sleep thread */
    for (int i = 0; i < NUM_SIGNALS; i++) {
        if (pthread_kill(sleep_thread, SIGUSR1) != 0) {
            perror("pthread_kill failed");
        }
        /* Send signals very fast to try to accumulate them */
        usleep(1000);
    }

    printf("Sender thread sent %d signals\n", NUM_SIGNALS);

    /* Wait a bit for signals to be delivered */
    sleep(2);
    done = 1;

    return NULL;
}

int main() {
    pthread_t sender_thread;
    struct sigaction sa;

    /* Set up signal handler */
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = sigusr1_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = 0;

    if (sigaction(SIGUSR1, &sa, NULL) != 0) {
        perror("sigaction failed");
        return 1;
    }

    printf("Starting signal accumulation test...\n");

    /* Create sleep thread */
    if (pthread_create(&sleep_thread, NULL, sleep_thread_func, NULL) != 0) {
        perror("pthread_create (sleep thread) failed");
        return 1;
    }

    /* Create sender thread */
    if (pthread_create(&sender_thread, NULL, sender_thread_func, NULL) != 0) {
        perror("pthread_create (sender thread) failed");
        return 1;
    }

    /* Wait for threads to complete */
    pthread_join(sender_thread, NULL);
    pthread_join(sleep_thread, NULL);

    printf("Test completed. Signals received: %d out of %d sent\n",
           signal_count, NUM_SIGNALS);

    /* Non-RT signals can coalesce, so we expect fewer than NUM_SIGNALS */
    /* But the test should not hang or crash */
    if (signal_count > 0) {
        printf("PASS: Test completed successfully\n");
        return 0;
    } else {
        printf("FAIL: No signals received\n");
        return 1;
    }
}

