/* Test for signal accumulation limit enforcement */
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pthread.h>
#include <string.h>
#include <errno.h>

#define NUM_SIGNALS 100
#define MAX_PENDING_DEFAULT 8

volatile int signal_count = 0;
volatile int done = 0;
volatile int ready = 0;
pthread_t target_thread;

void sigusr1_handler(int sig) {
    signal_count++;
}

void* target_thread_func(void* arg) {
    printf("Target thread started (tid=%ld)\n", (long)pthread_self());
    ready = 1;

    /* Keep thread busy to delay signal processing */
    while (!done) {
        /* Do some work to delay signal delivery */
        for (volatile int i = 0; i < 10000; i++) {
            ;
        }
    }

    printf("Target thread exiting, received %d signals\n", signal_count);
    return NULL;
}

void* sender_thread_func(void* arg) {
    printf("Sender thread started (tid=%ld)\n", (long)pthread_self());

    /* Wait for target thread to be ready */
    while (!ready) {
        usleep(1000);
    }

    /* Send many SIGUSR1 signals very rapidly to the target thread
     * to try to accumulate more than max_pending_signals */
    for (int i = 0; i < NUM_SIGNALS; i++) {
        if (pthread_kill(target_thread, SIGUSR1) != 0) {
            perror("pthread_kill failed");
        }
        /* Very short sleep to send signals faster than they can be processed */
        if (i % 10 == 0) {
            usleep(100);
        }
    }

    printf("Sender thread sent %d signals\n", NUM_SIGNALS);

    /* Wait for signals to be processed */
    sleep(2);
    done = 1;

    return NULL;
}

int main() {
    pthread_t sender_thread;
    struct sigaction sa;

    /* Set up signal handler */
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = sigusr1_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = 0;

    if (sigaction(SIGUSR1, &sa, NULL) != 0) {
        perror("sigaction failed");
        return 1;
    }

    printf("Starting signal limit test...\n");
    printf("Will send %d signals (more than default max_pending_signals=%d)\n",
           NUM_SIGNALS, MAX_PENDING_DEFAULT);

    /* Create target thread */
    if (pthread_create(&target_thread, NULL, target_thread_func, NULL) != 0) {
        perror("pthread_create (target thread) failed");
        return 1;
    }

    /* Create sender thread */
    if (pthread_create(&sender_thread, NULL, sender_thread_func, NULL) != 0) {
        perror("pthread_create (sender thread) failed");
        return 1;
    }

    /* Wait for threads to complete */
    pthread_join(sender_thread, NULL);
    pthread_join(target_thread, NULL);

    printf("Test completed. Signals received: %d out of %d sent\n",
           signal_count, NUM_SIGNALS);

    /* The test should complete without hanging or crashing.
     * Non-RT signals can be dropped, so we don't expect all to be received.
     * Under DynamoRIO with the fix, it should drop signals at the limit
     * rather than deadlock. */
    if (signal_count > 0 && signal_count <= NUM_SIGNALS) {
        printf("PASS: Test completed successfully (received some signals without deadlock)\n");
        return 0;
    } else {
        printf("FAIL: Unexpected signal count\n");
        return 1;
    }
}

