    printf("Total signals received: %d\n", sigusr1_count + sigalrm_count);

    /* The key is that the test completes without deadlock.
     * Under DynamoRIO with the fix, signals will be dropped at the limit
     * rather than causing a deadlock from lock acquisition. */
