/* Minimal test for signal dropping at max_pending_signals limit
 * This test verifies that non-RT signals are dropped at the limit
 * to prevent deadlock from special heap unit allocation.
 */
#include <stdio.h>
#include <stdlib.h>
#include <signal.h>
#include <unistd.h>
#include <pthread.h>
#include <string.h>

volatile int signals_received = 0;
volatile int ready_for_signals = 0;

void signal_handler(int sig) {
    signals_received++;
}

int main() {
    struct sigaction sa;
    int i;

    /* Set up signal handler */
    memset(&sa, 0, sizeof(sa));
    sa.sa_handler = signal_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = 0;

    if (sigaction(SIGUSR1, &sa, NULL) != 0) {
        perror("sigaction failed");
        return 1;
    }

    printf("Sending many SIGUSR1 signals to self...\n");

    /* Send many signals to self */
    for (i = 0; i < 20; i++) {
        if (kill(getpid(), SIGUSR1) != 0) {
            perror("kill failed");
            return 1;
        }
    }

    /* Allow signals to be delivered */
    sleep(1);

    printf("Signals received: %d\n", signals_received);

    /* The test passes if it completes without deadlock.
     * Under DynamoRIO with the fix, some signals may be dropped. */
    printf("PASS: Test completed without deadlock\n");
    return 0;
}
